class SAMLServiceProvider:
    def __init__(self, metadata=None):
        self.metadata = metadata or {}
        self.entity_id = getattr(settings, 'SAML_SP_ENTITY_ID', 'http://localhost:8000/saml/metadata/')
        self.acs_url = getattr(settings, 'SAML_ACS_URL', 'http://localhost:8000/saml/acs/')
        self.idp_entity_id = getattr(settings, 'SAML_IDP_ENTITY_ID', '')
        self.idp_sso_url = getattr(settings, 'SAML_IDP_SSO_URL', '')
    
    def generate_authn_request(self, relay_state=None):
        request_id = self._generate_request_id()
        issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
        
        authn_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{self.idp_sso_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
    AssertionConsumerServiceURL="{self.acs_url}">
    <saml:Issuer>{self.entity_id}</saml:Issuer>
</samlp:AuthnRequest>'''
        
        return authn_request, request_id
    
    def _generate_request_id(self):
        import uuid
        return f"_{uuid.uuid4().hex}"
    
    def process_response(self, saml_response):
        parser = SAMLParser(saml_response)
        parser.parse_xml()
        parser.validate_basic_structure()
        parser.validate_status()
        parser.validate_conditions()
        
        nameid = parser.get_nameid()
        attributes = parser.get_attributes()
        
        return {
            'nameid': nameid,
            'attributes': attributes,
        }


def create_or_update_user(nameid, attributes):
    if not nameid:
        raise ValueError("NameID is required")
    
    username = nameid.get('value', '')
    
    email = attributes.get('email', attributes.get('mail', ''))
    first_name = attributes.get('firstName', attributes.get('givenName', ''))
    last_name = attributes.get('lastName', attributes.get('surname', attributes.get('sn', '')))
    
    if isinstance(email, list):
        email = email[0] if email else ''
    if isinstance(first_name, list):
        first_name = first_name[0] if first_name else ''
    if isinstance(last_name, list):
        last_name = last_name[0] if last_name else ''
    
    username_clean = username.replace('@', '_').replace('.', '_')[:150]
    
    user, created = User.objects.get_or_create(
        username=username_clean,
        defaults={
            'email': email,
            'first_name': first_name[:30],
            'last_name': last_name[:150],
        }
    )
    
    if not created:
        user.email = email
        user.first_name = first_name[:30]
        user.last_name = last_name[:150]
        user.save()
    
    return user


@csrf_exempt
@require_http_methods(["POST"])
def assertion_consumer_service(request):
    try:
        saml_response = request.POST.get('SAMLResponse')
        relay_state = request.POST.get('RelayState', '/')
        
        if not saml_response:
            return HttpResponse("Missing SAMLResponse", status=400)
        
        sp = SAMLServiceProvider()
        user_data = sp.process_response(saml_response)
        
        user = create_or_update_user(user_data['nameid'], user_data['attributes'])
        
        user.backend = 'django.contrib.auth.backends.ModelBackend'
        login(request, user)
        
        request.session['saml_nameid'] = user_data['nameid']
        request.session['saml_attributes'] = user_data['attributes']
        request.session['saml_session_index'] = user_data.get('session_index')
        
        return HttpResponseRedirect(relay_state or '/')
        
    except SAMLValidationError as e:
        return HttpResponse(f"SAML Validation Error: {str(e)}", status=400)
    except Exception as e:
        return HttpResponse(f"Error processing SAML response: {str(e)}", status=500)


def initiate_sso(request):
    next_url = request.GET.get('next', '/')
    
    sp = SAMLServiceProvider()
    authn_request, request_id = sp.generate_authn_request(relay_state=next_url)
    
    encoded_request = base64.b64encode(authn_request.encode('utf-8')).decode('utf-8')
    
    context = {
        'saml_request': encoded_request,
        'relay_state': next_url,
        'idp_sso_url': sp.idp_sso_url,
    }
    
    return render(request, 'saml/sso_redirect.html', context)


